import{_ as a,o,c as e,ae as r}from"./chunks/framework.6gkcVjOI.js";const g=JSON.parse('{"title":"开发路线图","description":"claude-code-Go 开发路线图","frontmatter":{"title":"开发路线图","description":"claude-code-Go 开发路线图"},"headers":[],"relativePath":"zh/roadmap.md","filePath":"zh/roadmap.md","lastUpdated":1775207872000}'),l={name:"zh/roadmap.md"};function i(d,t,n,s,h,c){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="开发路线图" tabindex="-1">开发路线图 <a class="header-anchor" href="#开发路线图" aria-label="Permalink to &quot;开发路线图&quot;">​</a></h1><p>以下是 claude-code-Go 的开发路线图，分为三个阶段。</p><h2 id="概览" tabindex="-1">概览 <a class="header-anchor" href="#概览" aria-label="Permalink to &quot;概览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>状态</th><th>描述</th></tr></thead><tbody><tr><td>第一阶段</td><td>✅ 已完成</td><td>核心基础 — Agent loop、工具、权限、MCP、SSE、会话</td></tr><tr><td>第二阶段</td><td>✅ 已完成</td><td>增强功能 — Skills、多 Provider、会话恢复</td></tr><tr><td>第三阶段</td><td>🔮 规划中</td><td>高级功能 — IDE 集成、协作、云端</td></tr></tbody></table><hr><h2 id="第一阶段-基础架构-✅-已完成" tabindex="-1">第一阶段：基础架构 ✅ 已完成 <a class="header-anchor" href="#第一阶段-基础架构-✅-已完成" aria-label="Permalink to &quot;第一阶段：基础架构 ✅ 已完成&quot;">​</a></h2><p>第一阶段建立了 AI 编程助手的核心基础设施。</p><h3 id="已完成功能" tabindex="-1">已完成功能 <a class="header-anchor" href="#已完成功能" aria-label="Permalink to &quot;已完成功能&quot;">​</a></h3><ul><li><strong>Agent Loop</strong> — 基于 stop_reason 驱动的「思考→行动→观察」自主循环</li><li><strong>6 大内置工具</strong> — Read、Write、Edit、Glob、Grep、Bash</li><li><strong>权限系统</strong> — 三级权限模型，支持 glob 规则匹配与会话记忆</li><li><strong>MCP 集成</strong> — Model Context Protocol，stdio 传输、JSON-RPC</li><li><strong>SSE 流式</strong> — 逐 token 实时流式响应</li><li><strong>会话持久化</strong> — 保存和恢复对话状态</li><li><strong>Hooks 系统</strong> — 执行前后回调，扩展能力</li></ul><hr><h2 id="第二阶段-增强功能-✅-已完成" tabindex="-1">第二阶段：增强功能 ✅ 已完成 <a class="header-anchor" href="#第二阶段-增强功能-✅-已完成" aria-label="Permalink to &quot;第二阶段：增强功能 ✅ 已完成&quot;">​</a></h2><p>第二阶段添加了更强大的功能，提升可用性和灵活性。</p><h3 id="已完成功能-1" tabindex="-1">已完成功能 <a class="header-anchor" href="#已完成功能-1" aria-label="Permalink to &quot;已完成功能&quot;">​</a></h3><ul><li><strong>Skills 系统</strong> — 自定义命令和可重用工作流（如 <code>/review-pr</code>、<code>/deploy</code>）</li><li><strong>多 Provider 支持</strong> — Anthropic、OpenAI 及任何 OpenAI 兼容 API</li><li><strong>会话恢复</strong> — 加载之前的对话并无缝衔接</li><li><strong>增强工具</strong> — Diff 视图、树形可视化、网页抓取</li><li><strong>手动压缩</strong> — <code>/compact</code> 命令减少上下文大小</li><li><strong>自动更新</strong> — <code>/update</code> 命令检查版本并更新</li></ul><hr><h2 id="第三阶段-高级功能-🔮-规划中" tabindex="-1">第三阶段：高级功能 🔮 规划中 <a class="header-anchor" href="#第三阶段-高级功能-🔮-规划中" aria-label="Permalink to &quot;第三阶段：高级功能 🔮 规划中&quot;">​</a></h2><p>未来计划带来更高级的功能和更好的集成。</p><h3 id="规划功能" tabindex="-1">规划功能 <a class="header-anchor" href="#规划功能" aria-label="Permalink to &quot;规划功能&quot;">​</a></h3><ul><li><strong>VS Code 扩展</strong> — 原生 IDE 集成，丰富的 UI</li><li><strong>桌面应用</strong> — 独立 GUI，完整功能集</li><li><strong>团队协作</strong> — 共享工作流、团队仪表盘、权限管理</li><li><strong>云端 Agent</strong> — 远程执行、API 端点、监控</li><li><strong>插件市场</strong> — 社区创建的 Skills 和扩展</li></ul><h3 id="愿景" tabindex="-1">愿景 <a class="header-anchor" href="#愿景" aria-label="Permalink to &quot;愿景&quot;">​</a></h3><p>第三阶段的目标是让 claude-code-Go 成为成熟的开发环境，在保持 Go 简洁和高性能的同时，弥合 CLI 和 IDE 之间的差距。</p><hr><h2 id="参与贡献" tabindex="-1">参与贡献 <a class="header-anchor" href="#参与贡献" aria-label="Permalink to &quot;参与贡献&quot;">​</a></h2><p>想影响路线图？查看 <a href="/claude-code-Go/zh/feedback.html">反馈</a> 页面了解如何提交问题报告和功能请求。</p><hr><p><em>最后更新：2026 年 4 月</em></p>',26)])])}const u=a(l,[["render",i]]);export{g as __pageData,u as default};
